#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    int val;
    int neighborCount;
    struct Node **neighbors;
} Node;

// Simple queue for BFS
typedef struct {
    Node **data;
    int front, rear, size;
} Queue;

Queue* createQueue(int capacity) {
    Queue *q = (Queue*)malloc(sizeof(Queue));
    q->data = (Node**)malloc(sizeof(Node*) * capacity);
    q->front = q->rear = 0;
    q->size = capacity;
    return q;
}

int isEmpty(Queue *q) { return q->front == q->rear; }
void enqueue(Queue *q, Node *node) { q->data[q->rear++] = node; }
Node* dequeue(Queue *q) { return q->data[q->front++]; }

Node* cloneGraph(Node *root, int N) {
    if (!root) return NULL;
    Node **cloneMap = (Node**)calloc(N, sizeof(Node*));
    Queue *q = createQueue(N);
    // clone root
    Node *rootClone = (Node*)malloc(sizeof(Node));
    rootClone->val = root->val;
    rootClone->neighborCount = root->neighborCount;
    rootClone->neighbors = (Node**)malloc(sizeof(Node*) * root->neighborCount);
    cloneMap[root->val] = rootClone;
    enqueue(q, root);
    while (!isEmpty(q)) {
        Node *cur = dequeue(q);
        Node *curClone = cloneMap[cur->val];
        curClone->neighborCount = cur->neighborCount;
        curClone->neighbors = (Node**)malloc(sizeof(Node*) * cur->neighborCount);
        for (int i = 0; i < cur->neighborCount; ++i) {
            Node *nbr = cur->neighbors[i];
            if (!cloneMap[nbr->val]) {
                Node *nbrClone = (Node*)malloc(sizeof(Node));
                nbrClone->val = nbr->val;
                cloneMap[nbr->val] = nbrClone;
                enqueue(q, nbr);
            }
            curClone->neighbors[i] = cloneMap[nbr->val];
        }
    }
    free(q->data); free(q); free(cloneMap);
    return rootClone;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        // allocate original nodes
        Node **nodes = (Node**)malloc(sizeof(Node*) * N);
        for (int i = 0; i < N; ++i) {
            nodes[i] = (Node*)malloc(sizeof(Node));
            nodes[i]->val = i;
            nodes[i]->neighborCount = 0;
            nodes[i]->neighbors = NULL;
        }
        // read adjacency lines
        char line[100000];
        getchar(); // consume newline after N
        for (int i = 0; i < N; ++i) {
            if (!fgets(line, sizeof(line), stdin)) line[0] = '\0';
            // count numbers
            int cnt = 0;
            char *p = strtok(line, " \n");
            while (p) { cnt++; p = strtok(NULL, " \n"); }
            nodes[i]->neighborCount = cnt;
            nodes[i]->neighbors = (Node**)malloc(sizeof(Node*) * cnt);
            // second pass to fill
            int idx = 0;
            // reset tokenisation
            // need to read line again, so store it earlier
            // simpler: reuse line buffer by copying before tokenisation
            // We'll re-read using sscanf loop
            // Rewind pointer to start of line (we have it in line variable already)
            // Use strtok again
            // First, copy line to a temp buffer
            char temp[100000];
            strcpy(temp, line);
            p = strtok(temp, " \n");
            while (p) {
                int v = atoi(p);
                nodes[i]->neighbors[idx++] = nodes[v];
                p = strtok(NULL, " \n");
            }
        }
        // clone
        Node *clonedRoot = cloneGraph(nodes[0], N);
        // we don't need to free the whole graph for this problem
        printf("1\n");
        // free original nodes (optional)
        for (int i = 0; i < N; ++i) free(nodes[i]);
        free(nodes);
        (void)clonedRoot; // silence unused warning
    }
    return 0;
}

