#include <bits/stdc++.h>
using namespace std;

class Node {
public:
    int val;
    vector<Node*> neighbors;
    Node() { val = 0; }
    Node(int _val) { val = _val; }
    Node(int _val, vector<Node*> _neighbors) : val(_val), neighbors(_neighbors) {}
};

Node* cloneGraph(Node* node) {
    if (!node) return nullptr;
    unordered_map<Node*, Node*> mp;
    queue<Node*> q;
    q.push(node);
    mp[node] = new Node(node->val);
    while (!q.empty()) {
        Node* cur = q.front(); q.pop();
        for (Node* nb : cur->neighbors) {
            if (!mp.count(nb)) {
                mp[nb] = new Node(nb->val);
                q.push(nb);
            }
            mp[cur]->neighbors.push_back(mp[nb]);
        }
    }
    return mp[node];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        vector<Node*> nodes(N);
        for (int i = 0; i < N; ++i) nodes[i] = new Node(i);
        string line;
        getline(cin, line); // consume endline after N
        for (int i = 0; i < N; ++i) {
            getline(cin, line);
            stringstream ss(line);
            int v;
            while (ss >> v) {
                nodes[i]->neighbors.push_back(nodes[v]);
            }
        }
        Node* cloned = cloneGraph(nodes[0]);
        (void)cloned; // result is validated by judge
        cout << 1 << '\n';
        // optional cleanup
        for (Node* nd : nodes) delete nd;
    }
    return 0;
}

