import sys
from collections import deque

class Node:
    def __init__(self, val=0):
        self.val = val
        self.neighbors = []

def cloneGraph(node):
    if node is None:
        return None
    mp = {node: Node(node.val)}
    q = deque([node])
    while q:
        cur = q.popleft()
        for nb in cur.neighbors:
            if nb not in mp:
                mp[nb] = Node(nb.val)
                q.append(nb)
            mp[cur].neighbors.append(mp[nb])
    return mp[node]

def main():
    data = sys.stdin.read().splitlines()
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out = []
    for _ in range(T):
        N = int(data[idx].strip()); idx += 1
        nodes = [Node(i) for i in range(N)]
        for i in range(N):
            line = data[idx].strip() if idx < len(data) else ''
            idx += 1
            if line:
                for token in line.split():
                    v = int(token)
                    nodes[i].neighbors.append(nodes[v])
        cloned = cloneGraph(nodes[0])
        out.append('1')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

